_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec2 center = vec2 (.5,.7);
sunpos = vec2(.2,.08);
uv1 = (vUv-center)*uAspect.xy;
mask = clamp01(512*uv1.y);

z =1/(uv1.y);
rs0.x = uv1.x * z; rs0.y = z ;
rs    = vec2 (rs0.x, rs0.y+uTime*1);
water = texture(sampler_noise_hq,rs*mask) + texture(sampler_noise_hq,rs/4.0*mask+uTime/8)-1;
uv_wat = vec2(uv1.x, abs(uv1.y))-water/z*.25* mask; //z: mehr nahreflekt.

// S U N
sun = clamp01(.01/length(uv_wat-sunpos))*suncol;

// S K Y  B A C K G R O U N D
sky1 = .15*clamp01(.5-abs(uv1.y))*vec3 (.6,.8,1);

// C L O U D S  L A Y E R 1
uv4 = vec2 (uv_wat.x/4, pow(uv_wat.y,.5));
uv4.x += fract(uTime/131) * (1-uv4.y);
cld1 = lum(texture(sampler_noise_mq,uv4 ));
cld1 = vec3 (0,0,1);

// C L O U D S  F R O M  W A R P  S H A D E R
clouds = (texture(sampler_main, rs_clouds(uv_wat)));

//F O R E S T
float size = .9*vUv.x;
uv5 = uv_wat/8/size;
float wip = (sin(vUv.x*8+uTime*1))* (uv1.y*uv1.y)*.004/size;
float stamm = texture(sampler_noise_lq,vec2(uv5.x/2+wip+rand_preset.x,.04*uv5.y)*8).r-.5;
float zweig = texture(sampler_noise_lq,vec2(uv5.x*8,uv5.y*128-stamm/2)).r;
forest = (abs(uv5.y*32/size))*(1+.5*stamm)*(1+.4*zweig);
forest = clamp01(1-forest) ;
vec3 forest_col= 16*fwidth(forest*sqrt(sun))*(1+stamm)*size*treecol*(1-mask*.5);


ret = sun+ sky1*clamp01(1-lum(clouds)*3)+ clouds*clouds*8;
ret = ret * clamp01(1-forest*8) + forest_col ;
ret = ret*(1-mask*.0);
ret = ret+mask*texture(sampler_noise_lq,mask*(rs0/4+water*.01)).r*.4/z;//Grund
//ret = forest;

  fragColor = ret;
}
